import tarfile
import os

def extract_tar_file(tar_path, dest_dir):
    try:
        with tarfile.open(tar_path, 'r') as tar:
            tar.extractall(path=dest_dir)
        print(f"Tar file extracted to {dest_dir}")
    except Exception as e:
        print(f"Error extracting tar file: {e}")

